import{_ as t,c as o,o as i,aj as a}from"./chunks/framework.HLg5PcC2.js";const g=JSON.parse('{"title":"Document Debugger","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/document-debugger.md","filePath":"getting-started/document-debugger.md"}'),r={name:"getting-started/document-debugger.md"};function n(l,e,s,d,c,u){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="document-debugger" tabindex="-1">Document Debugger <a class="header-anchor" href="#document-debugger" aria-label="Permalink to “Document Debugger”">​</a></h1><p>The Document Debugger is a powerful development tool included with <code>primitive-app</code> that lets you inspect and manage documents and data in your application. It&#39;s invaluable for debugging data issues, testing model relationships, and understanding how your data is structured.</p><h2 id="accessing-the-debugger" tabindex="-1">Accessing the Debugger <a class="header-anchor" href="#accessing-the-debugger" aria-label="Permalink to “Accessing the Debugger”">​</a></h2><p>The Document Debugger is part of the Debugging Suite, available at <code>/debug/documents</code> in your app. By default, these routes are restricted to <strong>admin users only</strong> using the <code>requireAuth: &quot;admin&quot;</code> route meta.</p><p>You can also access it from the Debugging Suite home page at <code>/debug</code>.</p><h2 id="document-management" tabindex="-1">Document Management <a class="header-anchor" href="#document-management" aria-label="Permalink to “Document Management”">​</a></h2><p>The left sidebar shows all documents you have access to—both documents you own and documents shared with you.</p><h3 id="document-list-features" tabindex="-1">Document List Features <a class="header-anchor" href="#document-list-features" aria-label="Permalink to “Document List Features”">​</a></h3><ul><li><strong>Search</strong> — Filter documents by title or ID using the search bar</li><li><strong>Pagination</strong> — Navigate through large document lists (25 per page)</li><li><strong>Permission badges</strong> — See your access level for each document (Owner, Editor, Viewer)</li><li><strong>Active indicator</strong> — Shows which document is currently open</li></ul><h3 id="document-actions" tabindex="-1">Document Actions <a class="header-anchor" href="#document-actions" aria-label="Permalink to “Document Actions”">​</a></h3><p>For documents you own, you can:</p><ul><li><strong>Create</strong> — Click &quot;Add&quot; to create a new document</li><li><strong>Rename</strong> — Click the edit icon to rename a document</li><li><strong>Delete</strong> — Click the trash icon to delete a document (cannot delete the currently active document)</li><li><strong>Mass Delete</strong> — Delete multiple owned documents at once via the menu</li></ul><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Shared documents (where you&#39;re an Editor or Viewer) cannot be deleted—only the owner can delete a document.</p></div><h2 id="exploring-data" tabindex="-1">Exploring Data <a class="header-anchor" href="#exploring-data" aria-label="Permalink to “Exploring Data”">​</a></h2><p>When you select a document, the main panel shows all your js-bao models with their record counts. The debugger automatically discovers all models registered in your app.</p><h3 id="model-overview" tabindex="-1">Model Overview <a class="header-anchor" href="#model-overview" aria-label="Permalink to “Model Overview”">​</a></h3><p>Each model card displays:</p><ul><li><strong>Model name</strong> and table name</li><li><strong>Record count</strong> in the selected document</li><li>Click to navigate to the detailed per-model view</li></ul><h3 id="per-model-view" tabindex="-1">Per-Model View <a class="header-anchor" href="#per-model-view" aria-label="Permalink to “Per-Model View”">​</a></h3><p>Clicking a model takes you to a detailed view with a data table showing all records. From here you can:</p><p><strong>Filter records:</strong></p><ul><li>Add multiple filters with various operators (equals, contains, starts with, greater than, etc.)</li><li>Combine filters for complex queries</li><li>Clear individual filters or all at once</li></ul><p><strong>Sort records:</strong></p><ul><li>Sort by any field (ascending or descending)</li><li>Multi-field sorting with drag-to-reorder priority</li><li>Click column headers for quick single-field sorting</li></ul><p><strong>View data:</strong></p><ul><li>Toggle &quot;Show hidden fields&quot; to see internal fields (prefixed with <code>_</code>)</li><li>Expand JSON fields in a full-screen editor</li><li>See field relationships to other models</li></ul><h2 id="crud-operations" tabindex="-1">CRUD Operations <a class="header-anchor" href="#crud-operations" aria-label="Permalink to “CRUD Operations”">​</a></h2><p>The Document Debugger provides full Create, Read, Update, Delete capabilities:</p><h3 id="creating-records" tabindex="-1">Creating Records <a class="header-anchor" href="#creating-records" aria-label="Permalink to “Creating Records”">​</a></h3><ol><li>Click &quot;Add Record&quot; in the document header</li><li>Select which model to create a record for</li><li>Fill in the field values using type-aware editors</li><li>Click &quot;Create Record&quot;</li></ol><p>The form automatically handles different field types:</p><ul><li><strong>Text fields</strong> — Standard input</li><li><strong>Boolean fields</strong> — Toggle switch</li><li><strong>Date fields</strong> — Calendar picker</li><li><strong>Relationship fields</strong> — Dropdown of related records</li><li><strong>StringSet fields</strong> — Tag-style editor for adding/removing items</li><li><strong>JSON fields</strong> — Expandable textarea with pretty-print option</li></ul><h3 id="editing-records" tabindex="-1">Editing Records <a class="header-anchor" href="#editing-records" aria-label="Permalink to “Editing Records”">​</a></h3><ol><li>Click the edit icon on any record row</li><li>Modify field values in the dialog</li><li>Click &quot;Save Changes&quot;</li></ol><p>Note that the <code>id</code> field is read-only and cannot be modified.</p><h3 id="deleting-records" tabindex="-1">Deleting Records <a class="header-anchor" href="#deleting-records" aria-label="Permalink to “Deleting Records”">​</a></h3><ul><li><strong>Single record</strong> — Click the trash icon on a record row and confirm</li><li><strong>Mass delete</strong> — Select multiple records and delete them in batch</li></ul><h2 id="model-information" tabindex="-1">Model Information <a class="header-anchor" href="#model-information" aria-label="Permalink to “Model Information”">​</a></h2><p>Click the info icon on any model to view detailed schema information:</p><ul><li><strong>Fields</strong> — All fields with their types, indexes, and properties</li><li><strong>Indexed fields</strong> — Fields that are indexed for faster queries</li><li><strong>Unique constraints</strong> — Field combinations that must be unique</li><li><strong>Relationships</strong> — How this model connects to other models</li><li><strong>Instance methods</strong> — Custom methods defined on the model</li><li><strong>Static methods</strong> — Class-level methods like custom finders</li></ul><p>This is helpful for understanding your data model structure and debugging relationship issues.</p><h2 id="scoped-queries" tabindex="-1">Scoped Queries <a class="header-anchor" href="#scoped-queries" aria-label="Permalink to “Scoped Queries”">​</a></h2><p>All queries in the Document Debugger are <strong>scoped to the selected document</strong>. This means:</p><ul><li>Record counts show only records in that document</li><li>Filters apply only to data in the current document</li><li>Creating records saves them to the current document</li></ul><p>This matches how documents work in production—data is isolated per document unless you explicitly query across documents.</p><h2 id="disabling-in-production" tabindex="-1">Disabling in Production <a class="header-anchor" href="#disabling-in-production" aria-label="Permalink to “Disabling in Production”">​</a></h2><p>While the debugging suite routes are protected by admin authentication by default, you may want to remove them entirely in production builds. You can conditionally exclude the debug routes in your router configuration based on environment.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to “Next Steps”">​</a></h2><ul><li><strong><a href="./understanding-documents.html">Understanding Documents</a></strong> — Learn how documents and sharing work</li><li><strong><a href="./working-with-data.html">Working with Data</a></strong> — Define models and perform CRUD operations</li><li><strong><a href="./deploying-to-production.html">Deploying to Production</a></strong> — Deploy your app to Cloudflare Workers</li></ul>',49)])])}const m=t(r,[["render",n]]);export{g as __pageData,m as default};
